css:
* { margin: 0; padding: 0; box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; }
body { background: linear-gradient(160deg, #1e1b4b, #0a0a1a); color: white; display: flex; justify-content: center; padding: 40px 20px; min-height: 100vh; }
.player { width: 100%; max-width: 380px; }
.art { width: 100%; aspect-ratio: 1; background: linear-gradient(135deg, #6366f1, #a855f7); border-radius: 24px; display: flex; align-items: center; justify-content: center; font-size: 90px; margin-bottom: 24px; box-shadow: 0 30px 60px rgba(99,102,241,0.3); }
h2 { font-size: 24px; font-weight: 800; text-align: center; margin-bottom: 4px; }
.player > p { text-align: center; color: rgba(255,255,255,0.45); font-size: 14px; margin-bottom: 24px; }
.progress-track { height: 6px; background: rgba(255,255,255,0.1); border-radius: 999px; cursor: pointer; overflow: hidden; }
.progress-fill { height: 100%; width: 0%; background: linear-gradient(90deg, #818cf8, #c084fc); border-radius: 999px; transition: width 0.5s linear; }
.time-row { display: flex; justify-content: space-between; font-size: 12px; color: rgba(255,255,255,0.4); margin-top: 8px; font-weight: 600; }
.controls { display: flex; align-items: center; justify-content: center; gap: 24px; margin: 28px 0; }
.controls button { background: rgba(255,255,255,0.06); border: none; color: white; width: 50px; height: 50px; border-radius: 50%; font-size: 18px; cursor: pointer; }
.play-btn { width: 68px !important; height: 68px !important; font-size: 22px !important; background: linear-gradient(135deg, #818cf8, #c084fc) !important; }
.extra-controls { display: flex; align-items: center; justify-content: space-between; margin-bottom: 30px; }
.extra-controls button { background: rgba(255,255,255,0.06); border: none; color: rgba(255,255,255,0.6); width: 38px; height: 38px; border-radius: 10px; font-size: 14px; cursor: pointer; }
.extra-controls button.active { background: rgba(168,85,247,0.25); color: #c084fc; }
.volume { display: flex; align-items: center; gap: 10px; flex: 1; margin: 0 16px; }
.volume input { flex: 1; }
.queue h3 { font-size: 14px; font-weight: 700; color: rgba(255,255,255,0.5); margin-bottom: 14px; text-transform: uppercase; letter-spacing: 0.05em; }
.track-item { display: flex; align-items: center; gap: 14px; padding: 12px; border-radius: 12px; cursor: pointer; }
.track-item.active, .track-item:hover { background: rgba(255,255,255,0.05); }
.t-icon { font-size: 20px; }
.t-info { flex: 1; display: flex; flex-direction: column; }
.t-info span { font-size: 14px; font-weight: 600; }
.t-info small { font-size: 12px; color: rgba(255,255,255,0.4); }
.t-dur { font-size: 12px; color: rgba(255,255,255,0.4); font-weight: 600; }

js:
const tracks = [
  { title: 'Sahil Esintisi', artist: 'Lo-Fi Koleksiyonu', art: '🎵', dur: 204 },
  { title: 'Gece Yarısı', artist: 'Ambient Sounds', art: '🌙', dur: 250 },
  { title: 'Yağmur Sesi', artist: 'Doğa Kayıtları', art: '☔', dur: 302 },
  { title: 'Şömine', artist: 'Rahatlatıcı Sesler', art: '🔥', dur: 375 }
];

let currentIndex = 0;
let playing = false;
let progress = 0;
let timer = null;
let shuffle = false;
let repeat = false;

function formatTime(sec) {
  const m = Math.floor(sec / 60);
  const s = Math.floor(sec % 60);
  return `${m}:${s.toString().padStart(2, '0')}`;
}

function render() {
  const t = tracks[currentIndex];
  document.getElementById('title').textContent = t.title;
  document.getElementById('artist').textContent = t.artist;
  document.getElementById('art').textContent = t.art;
  document.getElementById('durTime').textContent = formatTime(t.dur);
  document.querySelectorAll('.track-item').forEach((el, i) => el.classList.toggle('active', i === currentIndex));
}

function togglePlay() {
  playing = !playing;
  document.getElementById('playBtn').textContent = playing ? '❚❚' : '▶';
  if (playing) {
    timer = setInterval(() => {
      progress += 1;
      const t = tracks[currentIndex];
      if (progress >= t.dur) {
        if (repeat) { progress = 0; } else { nextTrack(); return; }
      }
      updateProgress();
    }, 1000);
  } else {
    clearInterval(timer);
  }
}

function updateProgress() {
  const t = tracks[currentIndex];
  const pct = (progress / t.dur) * 100;
  document.getElementById('progressFill').style.width = pct + '%';
  document.getElementById('curTime').textContent = formatTime(progress);
}

function nextTrack() {
  currentIndex = shuffle ? Math.floor(Math.random() * tracks.length) : (currentIndex + 1) % tracks.length;
  progress = 0;
  updateProgress();
  render();
}

function prevTrack() {
  currentIndex = (currentIndex - 1 + tracks.length) % tracks.length;
  progress = 0;
  updateProgress();
  render();
}

function selectTrack(el, index) {
  currentIndex = index;
  progress = 0;
  updateProgress();
  render();
  if (!playing) togglePlay();
}

function toggleShuffle() {
  shuffle = !shuffle;
  document.getElementById('shuffleBtn').classList.toggle('active', shuffle);
}

function toggleRepeat() {
  repeat = !repeat;
  document.getElementById('repeatBtn').classList.toggle('active', repeat);
}

function setVolume(val) {
  console.log('Ses seviyesi:', val);
}

document.getElementById('progressTrack').addEventListener('click', (e) => {
  const rect = e.currentTarget.getBoundingClientRect();
  const pct = (e.clientX - rect.left) / rect.width;
  const t = tracks[currentIndex];
  progress = Math.floor(pct * t.dur);
  updateProgress();
});

render();
updateProgress();
